const LOGO_B64 = 'data:image/png;base64,';

'use strict';

let stream = null;
let capturedBlob = null;
let lastResult = null;
let userName = '';
let userPhotoDataUrl = '';
let pendingAction = null; // 'camera' or 'upload'
let pendingFile = null;

const $ = id => document.getElementById(id);

const btnCamera     = $('btnCamera');
const btnCapture    = $('btnCapture');
const btnRetake     = $('btnRetake');
const btnAnalyze    = $('btnAnalyze');
const btnReanalyze  = $('btnReanalyze');
const btnDownloadPdf= $('btnDownloadPdf');
const btnNameNext   = $('btnNameNext');
const fileInput     = $('fileInput');
const nameModal     = $('nameModal');
const cameraModal   = $('cameraModal');
const previewModal  = $('previewModal');
const loadingOverlay= $('loadingOverlay');
const dashboard     = $('dashboard');
const videoEl       = $('videoEl');
const previewCanvas = $('previewCanvas');
const progressBar   = $('progressBar');
const loadingStep   = $('loadingStep');
const cameraError   = $('cameraError');
const userNameInput = $('userNameInput');
const nameError     = $('nameError');

// ══ TOMBOL UTAMA → NAMA DULU ══
btnCamera.addEventListener('click', () => {
  pendingAction = 'camera';
  userNameInput.value = userName;
  show(nameModal);
  setTimeout(() => userNameInput.focus(), 100);
});

fileInput.addEventListener('change', e => {
  const file = e.target.files?.[0];
  if (!file) return;
  if (!['image/jpeg','image/png','image/webp'].includes(file.type)) {
    alert('Gunakan format JPEG, PNG, atau WebP.'); return;
  }
  pendingAction = 'upload';
  pendingFile = file;
  userNameInput.value = userName;
  show(nameModal);
  setTimeout(() => userNameInput.focus(), 100);
  fileInput.value = '';
});

let pendingFile = null;

// ══ NAMA MODAL ══
btnNameNext.addEventListener('click', submitName);
userNameInput.addEventListener('keydown', e => { if (e.key === 'Enter') submitName(); });

function submitName() {
  const val = userNameInput.value.trim();
  if (!val) {
    nameError.classList.remove('hidden');
    userNameInput.focus();
    return;
  }
  nameError.classList.add('hidden');
  userName = val;
  hide(nameModal);

  if (pendingAction === 'camera') {
    openCamera();
  } else if (pendingAction === 'upload' && pendingFile) {
    processUploadFile(pendingFile);
    pendingFile = null;
  }
  pendingAction = null;
}

// ══ KAMERA ══
$('closeCamera').addEventListener('click', closeCamera);

async function openCamera() {
  cameraError.textContent = '';
  show(cameraModal);
  try {
    stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 960 } },
    });
    videoEl.srcObject = stream;
  } catch (err) {
    cameraError.textContent = 'Akses kamera ditolak. Izinkan kamera dan coba lagi.';
  }
}

function closeCamera() { stopStream(); hide(cameraModal); }
function stopStream() {
  if (stream) { stream.getTracks().forEach(t => t.stop()); stream = null; }
  videoEl.srcObject = null;
}

btnCapture.addEventListener('click', () => {
  const w = videoEl.videoWidth || 640;
  const h = videoEl.videoHeight || 480;
  const tmp = document.createElement('canvas');
  tmp.width = w; tmp.height = h;
  const ctx = tmp.getContext('2d');
  ctx.save(); ctx.scale(-1,1); ctx.drawImage(videoEl,-w,0,w,h); ctx.restore();
  tmp.toBlob(blob => {
    capturedBlob = blob;
    userPhotoDataUrl = tmp.toDataURL('image/jpeg', 0.85);
    closeCamera();
    showPreview(tmp);
  }, 'image/jpeg', 0.92);
});

// ══ UPLOAD ══
function processUploadFile(file) {
  capturedBlob = file;
  const img = new Image();
  img.onload = () => {
    const tmp = document.createElement('canvas');
    tmp.width = img.width; tmp.height = img.height;
    tmp.getContext('2d').drawImage(img, 0, 0);
    userPhotoDataUrl = tmp.toDataURL('image/jpeg', 0.85);
    showPreview(tmp);
    URL.revokeObjectURL(img.src);
  };
  img.src = URL.createObjectURL(file);
}

// ══ PREVIEW ══
function showPreview(srcCanvas) {
  const ctx = previewCanvas.getContext('2d');
  previewCanvas.width = srcCanvas.width;
  previewCanvas.height = srcCanvas.height;
  ctx.drawImage(srcCanvas, 0, 0);
  show(previewModal);
}
$('closePreview').addEventListener('click', () => hide(previewModal));
btnRetake.addEventListener('click', () => {
  hide(previewModal);
  if (stream) openCamera(); else show(nameModal);
});
btnAnalyze.addEventListener('click', runAnalysis);

// ══ ANALISIS ══
const LOADING_STEPS = [
  { text: 'Mendeteksi landmark wajah...', progress: 15 },
  { text: 'Menyelaraskan dan memproses gambar...', progress: 30 },
  { text: 'Mensegmentasi zona wajah...', progress: 45 },
  { text: 'Menganalisis metrik kulit...', progress: 65 },
  { text: 'Mendeteksi jerawat & pigmentasi...', progress: 78 },
  { text: 'Menghitung skor kesehatan kulit...', progress: 90 },
  { text: 'Membuat rekomendasi personal...', progress: 97 },
];

async function runAnalysis() {
  if (!capturedBlob) return;
  hide(previewModal);
  show(loadingOverlay);
  dashboard.classList.add('hidden');

  let stepIdx = 0;
  const stepInterval = setInterval(() => {
    if (stepIdx < LOADING_STEPS.length) {
      loadingStep.textContent = LOADING_STEPS[stepIdx].text;
      progressBar.style.width = LOADING_STEPS[stepIdx].progress + '%';
      stepIdx++;
    }
  }, 700);

  try {
    const formData = new FormData();
    formData.append('file', capturedBlob, 'skin_capture.jpg');
    const res = await fetch('/analyze', { method: 'POST', body: formData });
    const data = await res.json();
    clearInterval(stepInterval);
    loadingStep.textContent = 'Selesai! ✨';
    progressBar.style.width = '100%';

    if (!res.ok) {
      setTimeout(() => { hide(loadingOverlay); alert(data.detail || 'Analisis gagal. Coba lagi.'); }, 500);
      return;
    }
    lastResult = data;
    setTimeout(() => {
      hide(loadingOverlay);
      renderDashboard(data);
      dashboard.classList.remove('hidden');
      dashboard.scrollIntoView({ behavior: 'smooth' });
    }, 600);
  } catch (err) {
    clearInterval(stepInterval);
    hide(loadingOverlay);
    alert('Koneksi gagal. Periksa koneksi internet Anda.');
  }
}

btnReanalyze.addEventListener('click', () => {
  dashboard.classList.add('hidden');
  window.scrollTo({ top: 0, behavior: 'smooth' });
});

// ══ DOWNLOAD PDF ══
btnDownloadPdf.addEventListener('click', () => {
  if (!lastResult) return;
  generatePDF(lastResult);
});

function calcZoneScorePDF(z) {
  const oil  = z.oil_level || 0;
  const dry  = z.dryness || 0;
  const pore = z.pore_visibility || 0;
  const red  = z.redness || 0;
  const tex  = {'Smooth':100,'Normal':70,'Rough':35,'Halus':100,'Kasar':35}[z.texture] || 70;
  return Math.max(0, Math.min(100,
    (100-oil*0.4)*0.2+(100-dry*0.8)*0.2+
    (100-pore*0.7)*0.2+(100-red*0.7)*0.2+tex*0.2
  ));
}

function generatePDF(data) {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const W = 210;
  const pink   = [240, 41, 123];
  const purple = [155, 107, 200];
  const teal   = [46, 196, 196];
  const ink    = [45, 18, 53];
  const muted  = [155, 126, 168];
  const pale   = [255, 232, 243];

  let y = 0;

  // ── Header background pink solid
  doc.setFillColor(240, 41, 123);
  doc.rect(0, 0, W, 48, 'F');

  // ── Logo Opshe kiri
  try { doc.addImage(LOGO_B64, 'PNG', 6, 4, 38, 38); } catch(e) {}

  // ── Judul tengah
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(22);
  doc.setFont('helvetica', 'bold');
  doc.text('LAPORAN ANALISIS KULIT', W / 2, 20, { align: 'center' });
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bolditalic');
  doc.text('Ai - Powered Skin Intelligence Report', W / 2, 30, { align: 'center' });

  // ── Tanggal
  const now = new Date();
  const tgl = now.toLocaleDateString('id-ID', { day:'2-digit', month:'long', year:'numeric' });
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(255, 220, 240);
  doc.text(tgl, W / 2, 40, { align: 'center' });

  y = 58;

  // ── User Profile Section
  const profileH = 42;
  doc.setFillColor(255, 232, 243);
  doc.roundedRect(10, y, W - 20, profileH, 4, 4, 'F');
  doc.setFillColor(240, 41, 123);
  doc.roundedRect(10, y, 3, profileH, 1, 1, 'F');

  // Foto user — proporsional persegi, tanpa lingkaran
  const photoSize = 34;
  const photoX = 17;
  const photoY = y + (profileH - photoSize) / 2;
  if (userPhotoDataUrl) {
    try {
      // Clip persegi dengan sudut rounded
      doc.setFillColor(240, 41, 123);
      doc.roundedRect(photoX - 1, photoY - 1, photoSize + 2, photoSize + 2, 3, 3, 'F');
      // Foto proporsional 1:1
      doc.addImage(userPhotoDataUrl, 'JPEG', photoX, photoY, photoSize, photoSize, undefined, 'FAST');
    } catch(e) {}
  }

  // Info user
  const infoX = userPhotoDataUrl ? photoX + photoSize + 8 : 18;
  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...teal);
  doc.text('✦ SKIN ANALYSIS REPORT', infoX, y + 10);

  doc.setFontSize(18);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...ink);
  doc.text(userName || 'Pengguna', infoX, y + 23);

  doc.setFontSize(7.5);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(...muted);
  doc.text(`Skor: ${data.overall_score}/100  |  Jenis Kulit: ${terjemahSkinType(data.skin_type)}  |  ${tgl}`, infoX, y + 33);

  y += profileH + 8;

  // ── Face Map Section ──
  const zones = data.zones || [];
  if (zones.length > 0) {

    // Selesai face map section

    const namaZonaPDF = {'Forehead':'Dahi','Nose':'Hidung','Left Cheek':'Pipi Kiri','Right Cheek':'Pipi Kanan','Chin':'Dagu'};
    const rawAvgPDF = zones.reduce((a,zz) => a + calcZoneScorePDF(zz), 0) / (zones.length || 1);
    const ratioPDF  = (data.overall_score || 60) / (rawAvgPDF || 1);
    const zscores = {};
    zones.forEach(z => {
      const s = Math.round(Math.max(0, Math.min(100, calcZoneScorePDF(z) * ratioPDF)));
      zscores[z.zone] = { score: s, zone: z };
    });

    function getZC(s) {
      if (s>=80) return [29,158,117];
      if (s>=60) return [55,138,221];
      if (s>=40) return [186,117,23];
      if (s>=20) return [216,90,48];
      return [163,45,45];
    }

    // ── Layout: Diagram wajah kiri + bar chart kanan ──
    const fX = 12, fY = y, fW = 78, fH = 105;
    const dX = fX + fW + 8, dW = W - dX - 10;

    // Background panel kiri
    doc.setFillColor(250, 245, 255);
    doc.roundedRect(fX, fY, fW, fH, 4, 4, 'F');
    doc.setDrawColor(200, 180, 230);
    doc.setLineWidth(0.3);
    doc.roundedRect(fX, fY, fW, fH, 4, 4, 'S');

    const fcx = fX + fW/2;
    const fcy = fY + fH/2 + 5;

    // Outline wajah
    doc.setDrawColor(210, 180, 230);
    doc.setLineWidth(0.4);
    doc.setLineDashPattern([1.5,1.5],0);
    doc.ellipse(fcx, fcy, 30, 38);
    doc.setLineDashPattern([],0);

    // Draw zone ellipse
    function drawZE(cx, cy, rx, ry, score, lbl) {
      const c = getZC(score);
      doc.setFillColor(c[0],c[1],c[2]);
      doc.setFillColor(
        Math.min(255,c[0]+185),
        Math.min(255,c[1]+185),
        Math.min(255,c[2]+185)
      );
      doc.setDrawColor(...c);
      doc.setLineWidth(1);
      doc.ellipse(cx, cy, rx, ry, 'FD');
      doc.setFontSize(5.5);
      doc.setFont('helvetica','bold');
      doc.setTextColor(...c);
      doc.text(lbl, cx, cy-2, {align:'center'});
      doc.setFontSize(10);
      doc.text(String(score), cx, cy+5, {align:'center'});
    }

    const dahi      = zscores['Forehead']    || zscores['Dahi']       || {score:70};
    const hidung    = zscores['Nose']        || zscores['Hidung']      || {score:70};
    const pipiKiri  = zscores['Left Cheek']  || zscores['Pipi Kiri']  || {score:70};
    const pipiKanan = zscores['Right Cheek'] || zscores['Pipi Kanan'] || {score:70};
    const dagu      = zscores['Chin']        || zscores['Dagu']        || {score:70};

    drawZE(fcx,      fcy-27, 20,11, dahi.score,      'DAHI');
    drawZE(fcx,      fcy+1,   8,12, hidung.score,    'HIDUNG');
    drawZE(fcx-21,   fcy+1,  11,15, pipiKiri.score,  'PIPI KIRI');
    drawZE(fcx+21,   fcy+1,  11,15, pipiKanan.score, 'PIPI KANAN');
    drawZE(fcx,      fcy+25, 14, 9, dagu.score,      'DAGU');

    // Dekorasi mata
    doc.setFillColor(180,160,200);
    doc.ellipse(fcx-11, fcy-12, 5.5, 2.5, 'F');
    doc.ellipse(fcx+11, fcy-12, 5.5, 2.5, 'F');
    // Bibir
    doc.setFillColor(240,41,123);
    doc.ellipse(fcx, fcy+16, 6, 2.5, 'F');

    // ── Panel kanan: bar chart ──
    const allZ = [
      {name:'Dahi',       d:dahi,      raw:dahi.zone      },
      {name:'Hidung',     d:hidung,    raw:hidung.zone    },
      {name:'Pipi Kiri',  d:pipiKiri,  raw:pipiKiri.zone  },
      {name:'Pipi Kanan', d:pipiKanan, raw:pipiKanan.zone },
      {name:'Dagu',       d:dagu,      raw:dagu.zone      },
    ];

    let dy2 = fY + 2;
    allZ.forEach(z => {
      const c    = getZC(z.d.score);
      const bMax = dW - 20;
      const bW   = Math.round((z.d.score/100)*bMax);

      // Nama zona
      doc.setFontSize(7.5);
      doc.setFont('helvetica','bold');
      doc.setTextColor(...c);
      doc.text(z.name, dX, dy2+4);

      // Bar background
      doc.setFillColor(235,228,245);
      doc.roundedRect(dX, dy2+6, bMax, 4.5, 1, 1, 'F');

      // Bar fill
      doc.setFillColor(...c);
      if (bW>0) doc.roundedRect(dX, dy2+6, bW, 4.5, 1, 1, 'F');

      // Skor
      doc.setFontSize(8);
      doc.setFont('helvetica','bold');
      doc.setTextColor(...c);
      doc.text(String(z.d.score), dX+bMax+3, dy2+10);

      // Detail mini
      if (z.raw) {
        doc.setFontSize(5.5);
        doc.setFont('helvetica','normal');
        doc.setTextColor(140,120,160);
        doc.text(
          'Minyak:'+Math.round(z.raw.oil_level||0)+'%  Pori:'+Math.round(z.raw.pore_visibility||0)+'%  Merah:'+Math.round(z.raw.redness||0)+'%',
          dX, dy2+14
        );
        dy2 += 19;
      } else {
        dy2 += 16;
      }
    });

    y += fH + 6;

    // Legend
    const leg2 = [
      {l:'Sangat Baik (80-100)',c:[29,158,117]},
      {l:'Baik (60-79)',        c:[55,138,221]},
      {l:'Cukup (40-59)',       c:[186,117,23]},
      {l:'Perlu Perhatian (<40)',c:[216,90,48]},
    ];
    let lx3 = 10;
    leg2.forEach(l => {
      doc.setFillColor(...l.c);
      doc.circle(lx3+2, y+2, 2, 'F');
      doc.setFontSize(6);
      doc.setFont('helvetica','normal');
      doc.setTextColor(100,80,130);
      doc.text(l.l, lx3+5.5, y+3);
      lx3 += 48;
    });
    y += 10;

    // Cegah duplikasi — skip ke score section
    doc.setFillColor(245, 240, 255);
    doc.roundedRect(10, y, W - 20, 8, 2, 2, 'F');
    doc.setFillColor(167, 139, 250);
    doc.roundedRect(10, y, 3, 8, 1, 1, 'F');
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(80, 40, 140);
    doc.text('AI FACE MAP — KONDISI PER ZONA WAJAH', 16, y + 5.5);
    y += 12;

    // Grid 5 zone cards
    const zoneW = (W - 20) / 5;
    const zoneH = 22;
    const zoneColors = {
      score80: [29, 158, 117],
      score60: [55, 138, 221],
      score40: [186, 117, 23],
      score20: [216, 90, 48],
      score0:  [163, 45, 45],
    };

    function getZoneColor(s) {
      if (s>=80) return zoneColors.score80;
      if (s>=60) return zoneColors.score60;
      if (s>=40) return zoneColors.score40;
      if (s>=20) return zoneColors.score20;
      return zoneColors.score0;
    }

    const namaZonaPDF = {'Forehead':'Dahi','Nose':'Hidung','Left Cheek':'Pipi Kiri','Right Cheek':'Pipi Kanan','Chin':'Dagu'};

    zones.forEach((z, i) => {
      const rawScore = calcZoneScorePDF(z);
      const ratio = data.overall_score / (zones.reduce((a,zz) => a + calcZoneScorePDF(zz), 0) / zones.length || 1);
      const score = Math.round(Math.max(0, Math.min(100, rawScore * ratio)));
      const col = getZoneColor(score);
      const xPos = 10 + i * zoneW;

      doc.setFillColor(col[0], col[1], col[2]);
      doc.setFillColor(col[0], col[1], col[2], 0.15);
      doc.roundedRect(xPos + 1, y, zoneW - 2, zoneH, 3, 3, 'F');
      doc.setDrawColor(...col);
      doc.setLineWidth(0.5);
      doc.roundedRect(xPos + 1, y, zoneW - 2, zoneH, 3, 3, 'S');

      // Zone name
      doc.setFontSize(6.5);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(...col);
      const zoneName = namaZonaPDF[z.zone] || z.zone;
      doc.text(zoneName, xPos + zoneW/2, y + 7, { align: 'center' });

      // Score
      doc.setFontSize(13);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(...col);
      doc.text(String(score), xPos + zoneW/2, y + 17, { align: 'center' });
    });

    y += zoneH + 6;

    // Mini legend
    const legendItems = [
      { label: 'Sangat Baik (80-100)', color: [29,158,117] },
      { label: 'Baik (60-79)', color: [55,138,221] },
      { label: 'Cukup (40-59)', color: [186,117,23] },
      { label: 'Perlu Perhatian (<40)', color: [216,90,48] },
    ];
    let lx = 10;
    legendItems.forEach(l => {
      doc.setFillColor(...l.color);
      doc.circle(lx + 2, y + 1.5, 2, 'F');
      doc.setFontSize(6);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(100, 80, 130);
      doc.text(l.label, lx + 5, y + 2.5);
      lx += 46;
    });
    y += 8;
  }

  // ── Score section
  doc.setFillColor(...pale);
  doc.roundedRect(10, y, W - 20, 32, 4, 4, 'F');
  doc.setFillColor(...pink);
  doc.roundedRect(10, y, 3, 32, 1, 1, 'F');

  doc.setFontSize(28);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...pink);
  doc.text(`${data.overall_score}`, 32, y + 20);
  doc.setFontSize(11);
  doc.setTextColor(...muted);
  doc.text('/100', 32, y + 28);

  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...ink);
  doc.text('Skor Kesehatan Kulit', 60, y + 12);

  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(...muted);
  doc.text(scoreDescription(data.overall_score), 60, y + 20, { maxWidth: 130 });

  doc.setFontSize(9);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(...purple);
  doc.text(`Jenis Kulit: ${terjemahSkinType(data.skin_type)}  |  Warna: ${terjemahSkinTone(data.skin_tone)}  |  Undertone: ${terjemahUndertone(data.undertone)}`, 60, y + 28);

  y += 42;

  // ── Section helper
  function sectionTitle(title) {
    doc.setFillColor(...pink);
    doc.rect(10, y, W - 20, 7, 'F');
    doc.setFontSize(10);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(255, 255, 255);
    doc.text(title, 14, y + 5);
    y += 11;
  }

  function twoColRow(label, value, isRight = false) {
    const x = isRight ? W / 2 + 5 : 14;
    doc.setFontSize(8.5);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...muted);
    doc.text(label, x, y);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...ink);
    doc.text(String(value), x + 45, y);
  }

  // ── Metrik Kulit
  sectionTitle('METRIK KULIT');
  const metrikRows = [
    ['Kadar Minyak', `${Math.round(data.oil_level)}%`],
    ['Kekeringan', `${Math.round(data.dryness)}%`],
    ['Visibilitas Pori', `${Math.round(data.pore_visibility)}%`],
    ['Kemerahan', `${Math.round(data.redness)}%`],
    ['Pigmentasi', `${Math.round(data.pigmentation)}%`],
    ['Bintik Gelap', `${data.dark_spot_count}`],
    ['Tekstur Kulit', terjemahTexture(data.skin_texture)],
    ['Lingkaran Hitam', terjemahLevel(data.dark_circle_level)],
    ['Garis Halus', terjemahLevel(data.fine_lines_level)],
  ];
  for (let i = 0; i < metrikRows.length; i += 2) {
    doc.setFillColor(i % 4 === 0 ? 252 : 255, 248, 252);
    doc.rect(10, y - 4, W - 20, 8, 'F');
    twoColRow(metrikRows[i][0], metrikRows[i][1], false);
    if (metrikRows[i + 1]) twoColRow(metrikRows[i+1][0], metrikRows[i+1][1], true);
    y += 8;
  }
  y += 4;

  // ── Analisis Jerawat
  sectionTitle('ANALISIS JERAWAT & NODA');
  const am = data.acne_metrics || {};
  const acneItems = [
    ['Jerawat', am.acne ?? 0],
    ['Komedo Putih', am.whitehead ?? 0],
    ['Komedo Hitam', am.blackhead ?? 0],
    ['Bekas Jerawat', am.acne_scar ?? 0],
  ];
  for (let i = 0; i < acneItems.length; i += 2) {
    doc.setFillColor(i % 4 === 0 ? 252 : 255, 248, 252);
    doc.rect(10, y - 4, W - 20, 8, 'F');
    twoColRow(acneItems[i][0], acneItems[i][1], false);
    if (acneItems[i+1]) twoColRow(acneItems[i+1][0], acneItems[i+1][1], true);
    y += 8;
  }
  y += 4;

  // ── Zona Wajah
  if (data.zones && data.zones.length > 0) {
    sectionTitle('ANALISIS PER ZONA WAJAH');
    const namaZona = {'Forehead':'Dahi','Nose':'Hidung','Left Cheek':'Pipi Kiri','Right Cheek':'Pipi Kanan','Chin':'Dagu'};
    data.zones.forEach(z => {
      doc.setFontSize(8.5);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(...pink);
      doc.text((namaZona[z.zone] || z.zone).toUpperCase(), 14, y);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(...ink);
      doc.text(
        `Minyak: ${Math.round(z.oil_level)}%  |  Kering: ${Math.round(z.dryness)}%  |  Pori: ${Math.round(z.pore_visibility)}%  |  Kemerahan: ${Math.round(z.redness)}%  |  Tekstur: ${terjemahTexture(z.texture)}`,
        14, y + 5
      );
      y += 11;
    });
    y += 2;
  }

  // ── Page 2
  doc.addPage();
  y = 15;

  // Mini header page 2
  doc.setFillColor(240, 41, 123);
  doc.rect(0, 0, W, 10, 'F');
  doc.setFontSize(8);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(255,255,255);
  doc.text(`OPSHE Beauty AI — Laporan Analisis Kulit | ${userName}`, 10, 7);
  y = 18;

  // ── Helper render step
  function renderStep(s) {
    if (y > 260) {
      doc.addPage();
      doc.setFillColor(240, 41, 123);
      doc.rect(0, 0, W, 10, 'F');
      doc.setFontSize(8);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(255,255,255);
      doc.text('OPSHE Beauty AI — Laporan Analisis Kulit | ' + (userName||''), 10, 7);
      y = 18;
    }
    doc.setFontSize(9);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(...pink);
    doc.text(s.step + '. ' + s.product_type, 14, y);
    y += 5;
    if (s.why) {
      doc.setFontSize(7.5);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(...muted);
      const wLines = doc.splitTextToSize(s.why, W - 34);
      doc.text(wLines, 18, y);
      y += wLines.length * 4.2 + 1;
    }
    if (s.ingredients && s.ingredients.length) {
      doc.setFontSize(7.5);
      doc.setFont('helvetica', 'bold');
      doc.setTextColor(...purple);
      const iLines = doc.splitTextToSize('Bahan: ' + s.ingredients.join(', '), W - 34);
      doc.text(iLines, 18, y);
      y += iLines.length * 4.2 + 1;
    }
    if (s.note && s.note !== 'null' && s.note !== null) {
      doc.setFontSize(7);
      doc.setFont('helvetica', 'italic');
      doc.setTextColor(...teal);
      const nLines = doc.splitTextToSize('Catatan: ' + s.note, W - 34);
      doc.text(nLines, 18, y);
      y += nLines.length * 4.2 + 1;
    }
    y += 4;
  }

  // ── Rutinitas Pagi
  sectionTitle('RUTINITAS PAGI');
  (data.morning_routine || []).forEach(s => renderStep(s));
  y += 4;

  // ── Rutinitas Malam
  sectionTitle('RUTINITAS MALAM');
  (data.night_routine || []).forEach(s => renderStep(s));

  // ── Footer semua halaman
  const pageCount = doc.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    const pageH = 297;
    doc.setFillColor(240, 41, 123);
    doc.rect(0, pageH - 20, W, 20, 'F');

    try { doc.addImage(LOGO_B64, 'PNG', 4, pageH - 19, 16, 16); } catch(e) {}

    doc.setFontSize(6);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(255, 255, 255);
    doc.text(
      'Hasil analisis merupakan estimasi berbasis AI dari citra wajah dan tidak menggantikan diagnosis atau konsultasi dengan dokter kulit.',
      24, pageH - 13, { maxWidth: W - 70 }
    );
    doc.setFontSize(5.5);
    doc.setTextColor(255, 220, 240);
    doc.text('@opshe.id', 24, pageH - 7);

    try { doc.addImage(LOGO_YBC_B64, 'PNG', W - 30, pageH - 19, 26, 16); } catch(e) {}

    doc.setFontSize(7);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(255, 255, 255);
    doc.text(`Hal. ${i} / ${pageCount}`, W / 2, pageH - 6, { align: 'center' });
  }

  const filename = `OPSHE_${userName.replace(/\s+/g,'_')}_${now.toISOString().slice(0,10)}.pdf`;
  doc.save(filename);
}

// ══ RENDER DASHBOARD ══
function renderDashboard(data) {
  renderUserProfile();
  renderFaceMap(data);
  renderScore(data);
  renderMetrics(data);
  renderAcne(data);
  renderZones(data.zones || []);
  renderRoutine(data.morning_routine || [], 'tabMorning');
  renderRoutine(data.night_routine || [], 'tabNight');
  renderWeekly(data.recommendations?.weekly_treatments || []);
  renderIngredients(data.recommendations?.ingredients_by_concern || {});
  renderDisclaimer(data.recommendations?.disclaimer);
}

function renderUserProfile() {
  $('userNameDisplay').textContent = userName || '—';
  const avatarImg = $('userAvatarImg');
  if (userPhotoDataUrl) {
    avatarImg.src = userPhotoDataUrl;
    avatarImg.style.display = 'block';
  }
}

const ZONE_IDS = {
  'Forehead':    { svg:'svgDahi',      svgS:'svgDahiScore',      bar:'barDahi',      barS:'barDahiScore'      },
  'Nose':        { svg:'svgHidung',    svgS:'svgHidungScore',    bar:'barHidung',    barS:'barHidungScore'    },
  'Left Cheek':  { svg:'svgPipiKiri',  svgS:'svgPipiKiriScore',  bar:'barPipiKiri',  barS:'barPipiKiriScore'  },
  'Right Cheek': { svg:'svgPipiKanan', svgS:'svgPipiKananScore', bar:'barPipiKanan', barS:'barPipiKananScore' },
  'Chin':        { svg:'svgDagu',      svgS:'svgDaguScore',      bar:'barDagu',      barS:'barDaguScore'      },
  'Dahi':        { svg:'svgDahi',      svgS:'svgDahiScore',      bar:'barDahi',      barS:'barDahiScore'      },
  'Hidung':      { svg:'svgHidung',    svgS:'svgHidungScore',    bar:'barHidung',    barS:'barHidungScore'    },
  'Pipi Kiri':   { svg:'svgPipiKiri',  svgS:'svgPipiKiriScore',  bar:'barPipiKiri',  barS:'barPipiKiriScore'  },
  'Pipi Kanan':  { svg:'svgPipiKanan', svgS:'svgPipiKananScore', bar:'barPipiKanan', barS:'barPipiKananScore' },
  'Dagu':        { svg:'svgDagu',      svgS:'svgDaguScore',      bar:'barDagu',      barS:'barDaguScore'      },
};
const ZONE_NAME_ID = {'Forehead':'Dahi','Nose':'Hidung','Left Cheek':'Pipi Kiri','Right Cheek':'Pipi Kanan','Chin':'Dagu'};

function zoneScoreColor(s) {
  if (s>=80) return '#1D9E75';
  if (s>=60) return '#378ADD';
  if (s>=40) return '#BA7517';
  if (s>=20) return '#D85A30';
  return '#A32D2D';
}
function zoneScoreColorLight(s) {
  if (s>=80) return 'rgba(29,158,117,0.22)';
  if (s>=60) return 'rgba(55,138,221,0.22)';
  if (s>=40) return 'rgba(186,117,23,0.22)';
  if (s>=20) return 'rgba(216,90,48,0.22)';
  return 'rgba(163,45,45,0.22)';
}

let _globalOverallScore = 0;
let _globalZones = [];

function calcZoneScore(z, overallScore) {
  const oil  = z.oil_level || 0;
  const dry  = z.dryness || 0;
  const pore = z.pore_visibility || 0;
  const red  = z.redness || 0;
  const tex  = {'Smooth':100,'Normal':70,'Rough':35,'Halus':100,'Kasar':35}[z.texture] || 70;
  const raw  = (100-oil*0.4)*0.2 + (100-dry*0.8)*0.2 +
               (100-pore*0.7)*0.2 + (100-red*0.7)*0.2 + tex*0.2;

  // Kalibrasikan zone score agar rata-rata konsisten dengan overall score
  if (_globalZones.length > 0 && overallScore > 0) {
    const rawAvg = _globalZones.reduce((a,zz) => {
      const o=zz.oil_level||0,d=zz.dryness||0,p=zz.pore_visibility||0,r=zz.redness||0;
      const t={'Smooth':100,'Normal':70,'Rough':35,'Halus':100,'Kasar':35}[zz.texture]||70;
      return a + (100-o*0.4)*0.2+(100-d*0.8)*0.2+(100-p*0.7)*0.2+(100-r*0.7)*0.2+t*0.2;
    }, 0) / _globalZones.length;
    const ratio = overallScore / (rawAvg || 1);
    return Math.round(Math.max(0, Math.min(100, raw * ratio)));
  }
  return Math.round(Math.max(0, Math.min(100, raw)));
}

function scoreToColor(s) {
  if (s >= 80) return '#00F5D4';
  if (s >= 60) return '#7FD4A0';
  if (s >= 40) return '#FFE600';
  if (s >= 20) return '#FF6B35';
  return '#FF006E';
}

function renderFaceMap(data) {
  const zones = data.zones || [];
  _globalOverallScore = data.overall_score || 0;
  _globalZones = zones;
  const scores = zones.map(z => ({ ...z, score: calcZoneScore(z, _globalOverallScore) }));

  // Foto
  const photoEl = document.getElementById('facemapPhoto');
  const noPhoto = document.getElementById('noPhoto');
  if (userPhotoDataUrl && photoEl) {
    photoEl.src = userPhotoDataUrl;
    photoEl.style.display = 'block';
    if (noPhoto) noPhoto.style.display = 'none';
    photoEl.onload = () => drawHeatmap(zones);
    if (photoEl.complete) drawHeatmap(zones);
  }

  // Stats
  if (scores.length) {
    const sorted = [...scores].sort((a,b) => b.score - a.score);
    const best  = ZONE_NAME_ID[sorted[0].zone] || sorted[0].zone;
    const worst = ZONE_NAME_ID[sorted[sorted.length-1].zone] || sorted[sorted.length-1].zone;
    const avg   = Math.round(scores.reduce((a,z)=>a+z.score,0)/scores.length);
    const sb = document.getElementById('statBest');   if(sb) sb.textContent = best;
    const sw = document.getElementById('statWorst');  if(sw) sw.textContent = worst;
    const sa = document.getElementById('statAvg');    if(sa) sa.textContent = avg;
  }

  // SVG + bars
  scores.forEach(z => {
    const ids = ZONE_IDS[z.zone];
    if (!ids) return;
    const col = zoneScoreColor(z.score);
    const colL = zoneScoreColorLight(z.score);

    const svgEl = document.getElementById(ids.svg);
    if (svgEl) { svgEl.setAttribute('fill', colL); svgEl.setAttribute('stroke', col); svgEl.setAttribute('stroke-width','2'); }

    const svgS = document.getElementById(ids.svgS);
    if (svgS) { svgS.textContent = z.score; svgS.setAttribute('fill', col); }

    const barEl = document.getElementById(ids.bar);
    if (barEl) { barEl.style.width = z.score+'%'; barEl.style.background = col; }

    const barS = document.getElementById(ids.barS);
    if (barS) { barS.textContent = z.score; barS.style.color = col; }
  });
}

function drawHeatmap(zones) {
  const canvas  = document.getElementById('facemapOverlay');
  const photoEl = document.getElementById('facemapPhoto');
  if (!canvas || !photoEl) return;
  const W = photoEl.offsetWidth || 300;
  const H = photoEl.offsetHeight || 400;
  canvas.width = W; canvas.height = H;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, W, H);

  const regions = {
    'Forehead':    {cx:0.50,cy:0.18,rx:0.40,ry:0.13},
    'Nose':        {cx:0.50,cy:0.50,rx:0.14,ry:0.16},
    'Left Cheek':  {cx:0.22,cy:0.53,rx:0.22,ry:0.20},
    'Right Cheek': {cx:0.78,cy:0.53,rx:0.22,ry:0.20},
    'Chin':        {cx:0.50,cy:0.78,rx:0.26,ry:0.13},
    'Dahi':        {cx:0.50,cy:0.18,rx:0.40,ry:0.13},
    'Hidung':      {cx:0.50,cy:0.50,rx:0.14,ry:0.16},
    'Pipi Kiri':   {cx:0.22,cy:0.53,rx:0.22,ry:0.20},
    'Pipi Kanan':  {cx:0.78,cy:0.53,rx:0.22,ry:0.20},
    'Dagu':        {cx:0.50,cy:0.78,rx:0.26,ry:0.13},
  };

  zones.forEach(z => {
    const reg = regions[z.zone];
    if (!reg) return;
    const score = calcZoneScore(z);
    const color = scoreToColor(score);
    const cx = reg.cx*W, cy = reg.cy*H;
    const rx = reg.rx*W, ry = reg.ry*H;
    const r = parseInt(color.slice(1,3),16);
    const g = parseInt(color.slice(3,5),16);
    const b = parseInt(color.slice(5,7),16);

    const grad = ctx.createRadialGradient(cx,cy,0,cx,cy,Math.max(rx,ry));
    grad.addColorStop(0, `rgba(${r},${g},${b},0.55)`);
    grad.addColorStop(0.7, `rgba(${r},${g},${b},0.25)`);
    grad.addColorStop(1, `rgba(${r},${g},${b},0)`);

    ctx.save();
    ctx.beginPath();
    ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI*2);
    ctx.fillStyle = grad;
    ctx.fill();
    ctx.restore();

    // Score label
    ctx.save();
    ctx.font = `bold ${Math.round(W*0.055)}px monospace`;
    ctx.textAlign = 'center';
    ctx.fillStyle = '#fff';
    ctx.shadowColor = color;
    ctx.shadowBlur = 10;
    ctx.fillText(score, cx, cy + W*0.02);
    ctx.restore();
  });
}

function renderScore(data) {
  const score = data.overall_score || 0;
  $('scoreNum').textContent = score;
  setTimeout(() => { $('scoreArc').style.strokeDashoffset = 314 - (score/100)*314; }, 100);
  $('scoreDesc').textContent = scoreDescription(score);
  $('skinTypeBadge').textContent = terjemahSkinType(data.skin_type) || '—';
  $('skinTone').textContent = terjemahSkinTone(data.skin_tone) || '—';
  $('undertone').textContent = terjemahUndertone(data.undertone) || '—';
}

function scoreDescription(score) {
  if (score >= 85) return 'Kesehatan kulit sangat baik — sedikit penyesuaian untuk hasil sempurna.';
  if (score >= 70) return 'Kesehatan kulit baik — perawatan terarah dapat mengatasi beberapa masalah.';
  if (score >= 55) return 'Kesehatan kulit cukup — rutinitas konsisten akan membuat perbedaan nyata.';
  if (score >= 40) return 'Ada beberapa masalah kulit — rutinitas personal sangat direkomendasikan.';
  return 'Beberapa masalah terdeteksi — segera mulai rutinitas perawatan kulit terstruktur.';
}

function terjemahSkinType(v) { return {Oily:'Berminyak',Dry:'Kering',Combination:'Kombinasi',Normal:'Normal'}[v]||v; }
function terjemahSkinTone(v) { return {Fair:'Cerah',Light:'Terang',Medium:'Sedang',Tan:'Tan',Deep:'Gelap'}[v]||v; }
function terjemahUndertone(v) { return {Cool:'Dingin',Warm:'Hangat',Neutral:'Netral'}[v]||v; }
function terjemahTexture(v) { return {Smooth:'Halus',Normal:'Normal',Rough:'Kasar'}[v]||v; }
function terjemahLevel(v) { return {None:'Tidak Ada',Light:'Ringan',Medium:'Sedang',Heavy:'Berat',Mild:'Ringan',Moderate:'Sedang',Severe:'Parah'}[v]||v; }

function renderMetrics(data) {
  const grid = $('metricsGrid');
  grid.innerHTML = '';
  const metrics = [
    { label:'Kadar Minyak',     value:data.oil_level,         unit:'%', bar:true },
    { label:'Kekeringan',        value:data.dryness,           unit:'%', bar:true },
    { label:'Visibilitas Pori',  value:data.pore_visibility,   unit:'%', bar:true },
    { label:'Kemerahan',         value:data.redness,           unit:'%', bar:true },
    { label:'Pigmentasi',        value:data.pigmentation,      unit:'%', bar:true },
    { label:'Bintik Gelap',      value:data.dark_spot_count,   unit:'', bar:false },
    { label:'Tekstur Kulit',     value:terjemahTexture(data.skin_texture), unit:'', bar:false, badge:true },
    { label:'Lingkaran Hitam',   value:terjemahLevel(data.dark_circle_level), unit:'', bar:false, badge:true },
    { label:'Garis Halus',       value:terjemahLevel(data.fine_lines_level), unit:'', bar:false, badge:true },
  ];
  metrics.forEach(m => {
    const card = document.createElement('div');
    card.className = 'metric-card';
    let html = '';
    if (m.bar) {
      const pct = Math.round(m.value||0);
      html = `<div class="metric-value">${pct}${m.unit}</div><div class="metric-bar"><div class="metric-bar-fill" style="width:${pct}%"></div></div>`;
    } else if (m.badge) {
      html = `<div class="metric-value" style="font-size:1.1rem">${m.value||'—'}</div><span class="metric-badge ${badgeClass(m.value)}">${m.value||'—'}</span>`;
    } else {
      html = `<div class="metric-value">${m.value??'—'}${m.unit}</div>`;
    }
    card.innerHTML = `<div class="metric-label">${m.label}</div>${html}`;
    grid.appendChild(card);
  });
}

function badgeClass(val) {
  if (['Halus','Normal','Tidak Ada','Ringan'].includes(val)) return 'badge-good';
  if (['Kasar','Berat','Parah'].includes(val)) return 'badge-bad';
  return 'badge-warn';
}

function renderAcne(data) {
  const am = data.acne_metrics || {};
  $('acneGrid').innerHTML = [
    { icon:'🔴', label:'Jerawat',       count:am.acne??0 },
    { icon:'⚪', label:'Komedo Putih',  count:am.whitehead??0 },
    { icon:'⚫', label:'Komedo Hitam',  count:am.blackhead??0 },
    { icon:'🟤', label:'Bekas Jerawat', count:am.acne_scar??0 },
  ].map(i=>`<div class="acne-card"><div class="acne-icon">${i.icon}</div><div class="acne-count">${i.count}</div><div class="acne-label">${i.label}</div></div>`).join('');
}

function renderZones(zones) {
  const nama = {'Forehead':'Dahi','Nose':'Hidung','Left Cheek':'Pipi Kiri','Right Cheek':'Pipi Kanan','Chin':'Dagu'};
  $('zonesGrid').innerHTML = zones.map(z=>`
    <div class="zone-card">
      <div class="zone-name">${nama[z.zone]||z.zone}</div>
      <div class="zone-row"><span>Minyak</span><span class="zone-val">${Math.round(z.oil_level)}%</span></div>
      <div class="zone-row"><span>Kering</span><span class="zone-val">${Math.round(z.dryness)}%</span></div>
      <div class="zone-row"><span>Pori</span><span class="zone-val">${Math.round(z.pore_visibility)}%</span></div>
      <div class="zone-row"><span>Kemerahan</span><span class="zone-val">${Math.round(z.redness)}%</span></div>
      <div class="zone-row"><span>Tekstur</span><span class="zone-val">${terjemahTexture(z.texture)}</span></div>
    </div>`).join('');
}

function renderRoutine(steps, id) {
  const el = $(id);
  if (!steps.length) { el.innerHTML='<p style="color:var(--muted)">Tidak ada langkah tersedia.</p>'; return; }
  el.innerHTML = `<div class="routine-steps">${steps.map(s=>`
    <div class="routine-step">
      <div class="step-num">${s.step}</div>
      <div class="step-body">
        <div class="step-product">${s.product_type}</div>
        <div class="step-why">${s.why||''}</div>
        <div class="step-ings">${(s.ingredients||[]).map(i=>`<span class="ing-chip">${i}</span>`).join('')}</div>
        ${s.note?`<div class="step-note">💡 ${s.note}</div>`:''}
      </div>
    </div>`).join('')}</div>`;
}

function renderWeekly(treatments) {
  const el = $('tabWeekly');
  if (!treatments.length) { el.innerHTML='<p style="color:var(--muted)">Tidak ada perawatan mingguan yang direkomendasikan.</p>'; return; }
  el.innerHTML = `<div class="weekly-cards">${treatments.map(t=>`
    <div class="weekly-card">
      <div class="weekly-type">${t.product_type}</div>
      <div class="weekly-why">${t.why||''}</div>
      <div class="step-ings">${(t.ingredients||[]).map(i=>`<span class="ing-chip">${i}</span>`).join('')}</div>
    </div>`).join('')}</div>`;
}

function renderIngredients(byConcern) {
  const el = $('tabIngredients');
  const entries = Object.entries(byConcern);
  if (!entries.length) { el.innerHTML='<p style="color:var(--muted)">Tidak ada masalah bahan aktif terdeteksi.</p>'; return; }
  const nama = {oily:'Berminyak',dry:'Kering',combination:'Kombinasi',normal:'Normal',sensitive:'Sensitif',acne:'Jerawat',hyperpigmentation:'Hiperpigmentasi',fine_lines:'Garis Halus',redness:'Kemerahan',dark_circles:'Lingkaran Hitam',dehydrated:'Dehidrasi'};
  el.innerHTML = entries.map(([k,ings])=>`
    <div class="ing-concern-block">
      <div class="concern-title">${nama[k]||k}</div>
      <div class="ing-list">${ings.map(i=>`<span class="ing-chip">${i}</span>`).join('')}</div>
    </div>`).join('');
}

function renderDisclaimer(text) {
  if (text) $('disclaimerText').textContent = text;
}

// ══ TABS ══
document.querySelectorAll('.tab').forEach(tab => {
  tab.addEventListener('click', () => {
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    tab.classList.add('active');
    ['tabMorning','tabNight','tabWeekly','tabIngredients'].forEach(id => {
      const el = $(id); if (el) el.classList.add('hidden');
    });
    const map = {morning:'tabMorning',night:'tabNight',weekly:'tabWeekly',ingredients:'tabIngredients'};
    const target = $(map[tab.dataset.tab]);
    if (target) target.classList.remove('hidden');
  });
});

function show(el) { el.classList.remove('hidden'); }
function hide(el) { el.classList.add('hidden'); }
